/**
 * Claude Agent
 *
 * Wrapper for spawning and managing a single Claude CLI process.
 */

import { spawn, type ChildProcess } from 'node:child_process';
import { EventEmitter } from 'node:events';
import type { Feature, ModelType } from '../types.js';

export interface AgentOptions {
  model: ModelType;
  maxBudget?: number;
  timeout?: number;
  cwd?: string;
}

export interface AgentResult {
  success: boolean;
  output: string;
  error?: string;
  duration: number;
}

export class ClaudeAgent extends EventEmitter {
  readonly id: string;
  private process: ChildProcess | null = null;
  private output: string[] = [];
  private errorOutput: string[] = [];
  private startTime: number = 0;

  constructor(
    id: string,
    private options: AgentOptions
  ) {
    super();
    this.id = id;
  }

  /**
   * Execute a feature task
   */
  async executeFeature(feature: Feature): Promise<AgentResult> {
    const prompt = this.buildPrompt(feature);
    return this.execute(prompt);
  }

  /**
   * Execute a raw prompt
   */
  async execute(prompt: string): Promise<AgentResult> {
    return new Promise((resolve) => {
      this.startTime = Date.now();
      this.output = [];
      this.errorOutput = [];

      const args = this.buildArgs(prompt);

      this.process = spawn('claude', args, {
        cwd: this.options.cwd || process.cwd(),
        shell: true,
        stdio: ['inherit', 'pipe', 'pipe'],
      });

      const timeout = this.options.timeout || 10 * 60 * 1000; // 10 min default
      const timeoutId = setTimeout(() => {
        this.kill('Timeout exceeded');
      }, timeout);

      this.process.stdout?.on('data', (data: Buffer) => {
        const text = data.toString();
        this.output.push(text);
        this.emit('output', text);
      });

      this.process.stderr?.on('data', (data: Buffer) => {
        const text = data.toString();
        this.errorOutput.push(text);
        this.emit('error', text);
      });

      this.process.on('error', (err) => {
        clearTimeout(timeoutId);
        resolve({
          success: false,
          output: this.output.join(''),
          error: err.message,
          duration: Date.now() - this.startTime,
        });
      });

      this.process.on('close', (code) => {
        clearTimeout(timeoutId);
        resolve({
          success: code === 0,
          output: this.output.join(''),
          error: code !== 0 ? this.errorOutput.join('') : undefined,
          duration: Date.now() - this.startTime,
        });
      });
    });
  }

  /**
   * Build command line arguments for claude CLI
   */
  private buildArgs(prompt: string): string[] {
    const args = ['-p'];

    if (this.options.model) {
      args.push('--model', this.options.model);
    }

    if (this.options.maxBudget) {
      args.push('--max-budget-usd', String(this.options.maxBudget));
    }

    args.push(JSON.stringify(prompt));

    return args;
  }

  /**
   * Build prompt for a feature
   */
  private buildPrompt(feature: Feature): string {
    return `You are working on feature ${feature.id}: ${feature.description}

Steps to complete:
${feature.steps.map((s, i) => `${i + 1}. ${s}`).join('\n')}

${feature.notes ? `Notes: ${feature.notes}` : ''}

Important:
- Follow the harness protocol in CLAUDE.md
- Update features.json when complete (set passes: true)
- Update progress.txt with session notes
- Commit only changes for this feature
`;
  }

  /**
   * Kill the agent process
   */
  kill(reason?: string): void {
    if (this.process) {
      this.emit('killed', reason);
      this.process.kill('SIGTERM');
      this.process = null;
    }
  }

  /**
   * Check if agent is running
   */
  isRunning(): boolean {
    return this.process !== null;
  }

  /**
   * Get agent PID
   */
  getPid(): number | undefined {
    return this.process?.pid;
  }
}

